Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <map>

using namespace std;

int countWordOccurrences(const string& filename, const string& word) {
    int count = 0;
    ifstream file(filename);
    if (!file.is_open()) {
        cout << "Error opening file." << endl;
        return -1;
    }

    string line;
    while (getline(file, line)) {
        stringstream ss(line);
        string wordInLine;
        while (getline(ss, wordInLine, ' ')) {
            if (wordInLine == word) {
                count++;
            }
        }
    }

    file.close();
    return count;
}

int main() {
    string filename, word;
    cout << "Enter the filename: ";
    cin >> filename;
    cout << "Enter the word to count: ";
    cin >> word;

    int occurrences = countWordOccurrences(filename, word);
    if (occurrences != -1) {
        cout << "The word '" << word << "' occurs " << occurrences << " times in the file." << endl;
    }

    return 0;
}
```

Here's how the program works:

1.  The `countWordOccurrences` function takes two parameters: the filename and the word to count. It opens the file and reads it line by line. For each line, it splits the line into words using spaces as delimiters and checks if the current word matches the target word. If it does, it increments the count.
2.  In the `main` function, the program prompts the user to enter the filename and the word to count. It then calls `countWordOccurrences` with these inputs and prints the result.
3.  The program handles errors by checking if the file can be opened successfully. If not, it prints an error message and returns -1.

